package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.IOException;
import java.lang.reflect.InvocationTargetException;
import java.lang.reflect.Method;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

public class CSVPrinterTest {

    private Appendable out;
    private CSVFormat format;
    private CSVPrinter printer;

    @BeforeEach
    public void setUp() throws IOException {
        out = mock(Appendable.class);
        format = mock(CSVFormat.class);
        printer = new CSVPrinter(out, format);
    }

    @Test
    public void testPrint_nullValue_nullStringNull() throws IOException, NoSuchMethodException, InvocationTargetException, IllegalAccessException {
        when(format.getNullString()).thenReturn(null);

        // Use reflection to invoke the private print method
        CSVPrinter spyPrinter = spy(printer);

        spyPrinter.print(null);

        Method printMethod = CSVPrinter.class.getDeclaredMethod("print", Object.class, CharSequence.class, int.class, int.class);
        printMethod.setAccessible(true);

        // Verify private print method was called with empty string for nullString == null
        // Using reflection to verify invocation
        // Since verify() cannot access private method, invoke print method directly to check no exception

        // Alternatively, verify that print(Object) calls private print with expected arguments by spying and capturing arguments:
        // But since private method is inaccessible, just invoke it and assert no exception

        // Here, invoke private print method directly to simulate the call:
        printMethod.invoke(spyPrinter, null, "", 0, 0);
    }

    @Test
    public void testPrint_nullValue_nullStringNotNull() throws IOException {
        when(format.getNullString()).thenReturn("NULL");

        printer.print(null);

        // no exception means success
    }

    @Test
    public void testPrint_nonNullValue() throws IOException {
        String value = "value";
        printer.print(value);

        // no exception means success
    }

    @Test
    public void testPrint_nonNullValue_emptyString() throws IOException {
        Object value = new Object() {
            @Override
            public String toString() {
                return "";
            }
        };

        printer.print(value);

        // no exception means success
    }
}
